CREATE TRIGGER LG_KSLINES_DEL_223_01 ON LG_223_01_KSLINES
FOR DELETE
AS
DECLARE @TRCODE    SMALLINT
DECLARE @TRDATE    DATETIME
DECLARE @TRSIGN    SMALLINT
DECLARE @CASHREF   INT
DECLARE @AMOUNT    FLOAT
DECLARE @REPORTNET FLOAT
DECLARE @TRNET FLOAT
DECLARE @TRCURR SMALLINT
DECLARE @CANCELLED SMALLINT
DECLARE @STATUS    SMALLINT
SELECT @TRCODE    = D.TRCODE,
       @TRDATE    = D.DATE_,
       @TRSIGN    = D.SIGN,
       @CASHREF   = D.CARDREF,
       @AMOUNT    = D.AMOUNT,
       @REPORTNET = D.REPORTNET,
       @TRNET = D.TRNET,
       @TRCURR = D.TRCURR,
       @CANCELLED = D.CANCELLED,
       @STATUS    = D.STATUS FROM DELETED D
EXECUTE LG_UPDATE_CASHTRANS_223_01 -1, @TRCODE, @TRDATE, @TRSIGN, @CASHREF, @AMOUNT, @REPORTNET, @TRNET, @TRCURR, @CANCELLED, @STATUS
